import { useLocation } from "react-router-dom";
import "./Title.css";

export default function Header() {
  const location = useLocation();

  const getTitle = (path) => {
    switch (path) {
      case "/":
        return "Home";
      case "/realtime":
        return "Real-time Cell Analysis";
      case "/classify":
        return "Cell Classification";
      case "/detect":
        return "Cell Counting";
      case "/history":
        return "History";
      case "/profile":
        return "Profile";
      default:
        return "Time Cell";
    }
  };

  return (
    <header className="app-header">
      <h2>{getTitle(location.pathname)}</h2>
    </header>
  );
}
